using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching capabilities for the research agent.
/// Uses DuckDuckGo's HTML endpoint for search (no API key required).
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _http;

    public WebSearchTool()
    {
        _http = new HttpClient();
        _http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        _http.Timeout = TimeSpan.FromSeconds(15);
    }

    public IEnumerable<AIFunction> AsFunctions() =>
    [
        AIFunctionFactory.Create(SearchWebAsync, nameof(SearchWebAsync),
            "Search the web for information on a query. Returns a list of result titles, URLs, and snippets."),
        AIFunctionFactory.Create(FetchPageAsync, nameof(FetchPageAsync),
            "Fetch the text content of a specific web page URL for detailed reading."),
    ];

    [Description("Search the web for information. Returns titles, URLs, and snippets.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query")] string query,
        [Description("Maximum number of results to return (default 5)")] int maxResults = 5)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var formContent = new FormUrlEncodedContent([new("q", query)]);
            var response = await _http.PostAsync("https://html.duckduckgo.com/html/", formContent);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();
            return ParseSearchResults(html, maxResults);
        }
        catch (Exception ex)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"  ⚠ Search failed: {ex.Message}");
            Console.ResetColor();
            return [new("No results", "", $"Search failed: {ex.Message}")];
        }
    }

    [Description("Fetch and extract the text content of a web page.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🌐 Fetching: {url}");
        Console.ResetColor();

        try
        {
            var html = await _http.GetStringAsync(url);
            var text = StripHtmlToText(html);

            // Truncate to avoid exceeding token limits
            const int maxLength = 6000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated...]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html, int maxResults)
    {
        var results = new List<SearchResult>();

        // Match DuckDuckGo HTML result blocks
        var linkMatches = ResultLinkPattern().Matches(html);
        var snippetMatches = ResultSnippetPattern().Matches(html);

        for (int i = 0; i < Math.Min(linkMatches.Count, maxResults); i++)
        {
            var linkMatch = linkMatches[i];
            var rawUrl = WebUtility.HtmlDecode(linkMatch.Groups[1].Value);
            var title = StripHtml(WebUtility.HtmlDecode(linkMatch.Groups[2].Value));

            // DuckDuckGo wraps URLs in a redirect; extract the real URL
            var actualUrl = ExtractRealUrl(rawUrl);

            var snippet = i < snippetMatches.Count
                ? StripHtml(WebUtility.HtmlDecode(snippetMatches[i].Groups[1].Value))
                : "";

            if (!string.IsNullOrWhiteSpace(title))
                results.Add(new SearchResult(title.Trim(), actualUrl, snippet.Trim()));
        }

        return results;
    }

    private static string ExtractRealUrl(string ddgUrl)
    {
        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded_url>&...
        var match = UddgPattern().Match(ddgUrl);
        if (match.Success)
            return WebUtility.UrlDecode(match.Groups[1].Value);
        return ddgUrl;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagPattern().Replace(html, "");
        return CollapseWhitespace().Replace(text, " ").Trim();
    }

    private static string StripHtmlToText(string html)
    {
        // Remove script/style blocks
        var cleaned = ScriptStylePattern().Replace(html, " ");
        // Remove tags
        cleaned = HtmlTagPattern().Replace(cleaned, " ");
        // Decode entities
        cleaned = WebUtility.HtmlDecode(cleaned);
        // Collapse whitespace into single spaces/newlines
        cleaned = MultipleSpaces().Replace(cleaned, " ");
        cleaned = MultipleNewlines().Replace(cleaned, "\n\n");
        return cleaned.Trim();
    }

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]+href="([^"]*)"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultLinkPattern();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultSnippetPattern();

    [GeneratedRegex("""uddg=([^&]+)""")]
    private static partial Regex UddgPattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagPattern();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStylePattern();

    [GeneratedRegex(@"[^\S\n]+")]
    private static partial Regex MultipleSpaces();

    [GeneratedRegex(@"\n{3,}")]
    private static partial Regex MultipleNewlines();
}

public sealed record SearchResult(string Title, string Url, string Snippet);

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// An in-memory notebook that the agent uses to record and organize research findings.
/// Notes persist for the duration of the research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];
    private int _nextId = 1;

    public IEnumerable<AIFunction> AsFunctions() =>
    [
        AIFunctionFactory.Create(AddNote, nameof(AddNote),
            "Save a research note with a topic label and detailed content."),
        AIFunctionFactory.Create(GetAllNotes, nameof(GetAllNotes),
            "Retrieve all saved research notes."),
        AIFunctionFactory.Create(GetNotesByTopic, nameof(GetNotesByTopic),
            "Retrieve research notes filtered by a specific topic."),
    ];

    [Description("Save a research note. Use this to record important findings.")]
    public string AddNote(
        [Description("A short topic label for the note (e.g. 'Key Statistics', 'Background')")] string topic,
        [Description("The detailed content of the note")] string content)
    {
        var note = new Note(_nextId++, topic, content);
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkGreen;
        Console.WriteLine($"  📝 Note #{note.Id} saved: \"{topic}\"");
        Console.ResetColor();

        return $"Note #{note.Id} saved under topic \"{topic}\".";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return FormatNotes(_notes);
    }

    [Description("Retrieve research notes filtered by topic.")]
    public string GetNotesByTopic(
        [Description("The topic to filter by (case-insensitive partial match)")] string topic)
    {
        var matched = _notes
            .Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matched.Count == 0)
            return $"No notes found for topic \"{topic}\".";

        return FormatNotes(matched);
    }

    /// <summary>Returns the raw note list for programmatic access.</summary>
    public IReadOnlyList<Note> Notes => _notes.AsReadOnly();

    private static string FormatNotes(List<Note> notes)
    {
        var sb = new StringBuilder();
        sb.AppendLine($"=== {notes.Count} note(s) ===");
        foreach (var note in notes)
        {
            sb.AppendLine($"--- Note #{note.Id} [{note.Topic}] ---");
            sb.AppendLine(note.Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

public sealed record Note(int Id, string Topic, string Content);

