using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// ── Configuration ──────────────────────────────────────────────────────
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: OPENAI_API_KEY environment variable is required.");
    Console.Error.WriteLine("Optional: OPENAI_MODEL (default: gpt-4o-mini), OPENAI_BASE_URL");
    return 1;
}

// ── Build the AI chat client with automatic function-calling ───────────
var credential = new System.ClientModel.ApiKeyCredential(apiKey);
OpenAIClientOptions? clientOptions = baseUrl is not null
    ? new() { Endpoint = new Uri(baseUrl) }
    : null;

var openAIClient = clientOptions is not null
    ? new OpenAIClient(credential, clientOptions)
    : new OpenAIClient(credential);

IChatClient chatClient = openAIClient
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ── Register tools ─────────────────────────────────────────────────────
var webSearch = new WebSearchTool();
var notebook = new NoteTakingTool();

var tools = new List<AITool>();
tools.AddRange(webSearch.AsFunctions());
tools.AddRange(notebook.AsFunctions());

var chatOptions = new ChatOptions
{
    Tools = tools,
    Temperature = 0.2f,
};

// ── Agent system prompt ────────────────────────────────────────────────
const string SystemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic and
    produce a well-organized summary of your findings.

    You have access to the following tools:
    - SearchWebAsync: Search the web for information on a query.
    - FetchPageAsync: Fetch and read the full text of a specific URL.
    - AddNote: Save important findings as notes with topic labels.
    - GetAllNotes: Retrieve all your saved notes.
    - GetNotesByTopic: Retrieve notes filtered by topic.

    Follow this research process:
    1. Break the topic into key sub-questions.
    2. Search the web for each sub-question.
    3. Read promising pages for deeper detail when snippets aren't enough.
    4. Save important facts, statistics, and insights as notes using AddNote.
    5. After gathering enough information, retrieve your notes and produce a
       comprehensive, well-structured summary with key findings, organized
       by sub-topic.

    Always cite your sources with URLs where possible.
    Be thorough but concise—aim for quality over quantity.
    """;

// ── Interactive loop ───────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════════════╗");
Console.WriteLine("║          🔬 AI Research Agent                   ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.  ║");
Console.WriteLine("╚══════════════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
        topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine("(The agent will search the web, take notes, and summarize findings)");
    Console.WriteLine();
    Console.ResetColor();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, SystemPrompt),
        new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    try
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);

        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══════════════════ Research Summary ═══════════════════");
        Console.ResetColor();
        Console.WriteLine();
        Console.WriteLine(response.Text);
        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══════════════════════════════════════════════════════");
        Console.ResetColor();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("Goodbye!");
return 0;

